  1→import {
  2→  type ReactNode,
  3→  type RefObject,
  4→  useCallback,
  5→  useEffect,
  6→  useMemo,
  7→  useRef,
  8→  useState,
  9→} from 'react';
 10→import './actions_dropdown.scss';
 11→
 12→export interface DropdownAction {
 13→  label: string;
 14→  shortcut?: ReactNode;
 15→  onClick?: () => void;
 16→}
 17→
 18→export interface DropdownSection {
 19→  title?: string;
 20→  actions: DropdownAction[];
 21→}
 22→
 23→interface ActionsDropdownProps {
 24→  sections: DropdownSection[];
 25→  open: boolean;
 26→  onClose: () => void;
 27→  triggerRef?: RefObject<HTMLButtonElement | null>;
 28→}
 29→
 30→export function ActionsDropdown({
 31→  sections,
 32→  open,
 33→  onClose,
 34→  triggerRef,
 35→}: ActionsDropdownProps) {
 36→  const [activeIndex, setActiveIndex] = useState(0);
 37→  const dropdownRef = useRef<HTMLDivElement>(null);
 38→
 39→  const flatActions = useMemo(
 40→    () => sections.flatMap(s => s.actions),
 41→    [sections],
 42→  );
 43→
 44→  useEffect(() => {
 45→    if (open && dropdownRef.current) {
 46→      setActiveIndex(0);
 47→      dropdownRef.current.focus();
 48→    }
 49→  }, [open]);
 50→
 51→  const executeAction = useCallback(
 52→    (index: number) => {
 53→      flatActions[index]?.onClick?.();
 54→      onClose();
 55→    },
 56→    [
 57→      flatActions,
 58→      onClose,
 59→    ],
 60→  );
 61→
 62→  useEffect(() => {
 63→    if (!open) return;
 64→
 65→    function handleKeyDown(e: KeyboardEvent) {
 66→      if (e.key === 'k' && e.metaKey) {
 67→        e.preventDefault();
 68→        e.stopPropagation();
 69→        onClose();
 70→        return;
 71→      }
 72→
 73→      if (e.key === 'Escape') {
 74→        e.preventDefault();
 75→        e.stopPropagation();
 76→        onClose();
 77→        return;
 78→      }
 79→
 80→      if (e.key === 'ArrowDown') {
 81→        e.preventDefault();
 82→        e.stopPropagation();
 83→        setActiveIndex(i => (i < flatActions.length - 1 ? i + 1 : 0));
 84→        return;
 85→      }
 86→
 87→      if (e.key === 'ArrowUp') {
 88→        e.preventDefault();
 89→        e.stopPropagation();
 90→        setActiveIndex(i => (i > 0 ? i - 1 : flatActions.length - 1));
 91→        return;
 92→      }
 93→
 94→      if (e.key === 'Enter') {
 95→        e.preventDefault();
 96→        e.stopPropagation();
 97→        executeAction(activeIndex);
 98→      }
 99→    }
100→
101→    window.addEventListener('keydown', handleKeyDown, true);
102→    return () => window.removeEventListener('keydown', handleKeyDown, true);
103→  }, [
104→    open,
105→    flatActions.length,
106→    activeIndex,
107→    onClose,
108→    executeAction,
109→  ]);
110→
111→  useEffect(() => {
112→    if (!open) return;
113→
114→    function handleClickOutside(e: MouseEvent) {
115→      const target = e.target as Node;
116→      if (dropdownRef.current && !dropdownRef.current.contains(target)) {
117→        if (triggerRef?.current?.contains(target)) return;
118→        onClose();
119→      }
120→    }
121→
122→    document.addEventListener('mousedown', handleClickOutside);
123→    return () => document.removeEventListener('mousedown', handleClickOutside);
124→  }, [
125→    open,
126→    onClose,
127→    triggerRef,
128→  ]);
129→
130→  useEffect(() => {
131→    if (!open) return;
132→    const container = dropdownRef.current;
133→    if (!container) return;
134→
135→    const activeElement = container.querySelector<HTMLElement>(
136→      `[data-dropdown-index="${activeIndex}"]`,
137→    );
138→    activeElement?.scrollIntoView({ block: 'nearest' });
139→  }, [
140→    open,
141→    activeIndex,
142→  ]);
143→
144→  if (!open || flatActions.length === 0) return null;
145→
146→  let flatIndex = 0;
147→
148→  return (
149→    <div
150→      className="actions-dropdown"
151→      ref={dropdownRef}
152→      role="menu"
153→      aria-label="Available actions"
154→      tabIndex={-1}
155→    >
156→      {sections.map((section, sectionIndex) => (
157→        <div
158→          key={section.title ?? `section-${sectionIndex}`}
159→          className="actions-dropdown__section"
160→          role="group"
161→          aria-label={section.title}
162→        >
163→          {sectionIndex > 0 && (
164→            <div className="actions-dropdown__separator" role="separator" />
165→          )}
166→          {section.title && (
167→            <div className="actions-dropdown__section-title">
168→              {section.title}
169→            </div>
170→          )}
171→          {section.actions.map(action => {
172→            const idx = flatIndex++;
173→            return (
174→              <button
175→                key={action.label}
176→                id={`action-item-${idx}`}
177→                className={`actions-dropdown__item${idx === activeIndex ? ' actions-dropdown__item--active' : ''}`}
178→                data-dropdown-index={idx}
179→                role="menuitem"
180→                type="button"
181→                onClick={() => executeAction(idx)}
182→                onMouseEnter={() => setActiveIndex(idx)}
183→              >
184→                <span className="actions-dropdown__label">{action.label}</span>
185→                {action.shortcut && (
186→                  <span className="actions-dropdown__shortcut">
187→                    {action.shortcut}
188→                  </span>
189→                )}
190→              </button>
191→            );
192→          })}
193→        </div>
194→      ))}
195→    </div>
196→  );
197→}
